{"code": "import json

# Load 2015 metadata to get article IDs and region mapping
metadata_file = locals().get('var_functions.query_db:5')
with open(metadata_file, 'r') as f:
    metadata_2015 = json.load(f)

# Create article_id to region mapping
article_regions = {}
article_ids_2015 = []
for item in metadata_2015:
    article_id = str(item['article_id'])  # MongoDB stores as string
    article_regions[article_id] = item['region']
    article_ids_2015.append(article_id)

print('__RESULT__:')
print(json.dumps({
    "total_2015_article_ids": len(article_ids_2015),
    "sample_mapping": {k: article_regions[k] for k in list(article_regions.keys())[:5]}
}))"}

